<?php declare(strict_types=1);namespace App\Controllers;use App\Services\{ChannelService,HealthMonitor,PlaylistService,StreamService,StreamingHealthService,VideoService};final class DashboardController extends Controller{public function __construct(private StreamService $streams,private ChannelService $channels,private PlaylistService $playlists,private VideoService $videos,private HealthMonitor $health,private StreamingHealthService $v4){}public function index():never{$active=$this->streams->active();$this->view('dashboard',['active'=>$active,'channels'=>$this->channels->all(),'playlists'=>$this->playlists->all(),'videos'=>$this->videos->all(),'health'=>$this->health->snapshot($active),'v4'=>$this->v4->snapshot($active)]);}public function health():never{header('Content-Type: application/json');echo json_encode($this->v4->snapshot($this->streams->active()));exit;}}
